mapper.select:
select count(1)
from jst_order_main o
where o.del_flag = '0'
  and 
  and o.create_time  >=  #{startTime}
  and o.create_time  <  #{endTime}

select o.order_id as orderId, o.order_no as orderNo, o.user_id as userId, coalesce(nullif(u.real_name, ''), u.nickname) as userName, o.order_type as orderType, o.net_pay_amount as payAmount, o.order_status as status, o.create_time as createTime from jst_order_main o left join jst_user u on u.user_id = o.user_id and u.del_flag = '0' where o.del_flag = '0' and
and o.order_status = #{status}
and o.create_time >= #{startTime}
and o.create_time < #{endTime}
order by o.create_time desc, o.order_id desc
